/* techniques q21 (62 mục) — R6 sửa lỗi */
window.__LIBQ=window.__LIBQ||{};window.__LIBQ["tien-nghich"]=window.__LIBQ["tien-nghich"]||{};window.__LIBQ["tien-nghich"]["q21"]=window.__LIBQ["tien-nghich"]["q21"]||{};window.__LIBQ["tien-nghich"]["q21"]["techniques"]={"updatedAt":"2026-07-16","count":62,"techniques":[{"id":"cam-tran-coc","name":"Cấm trận cốc","cn":"","loai":"khac","loaiLabel":"Trận pháp/cấm chế","phamCap":"Không rõ","hePhai":"Đạo Cổ","soHuu":["Huyền La"],"blurb":"Tuyệt cốc trong dãy núi Đạo Cổ có vách đá đầy ký hiệu ấn ký, mỗi ấn ký ẩn chứa trận pháp cấm chế. Huyền La phong cấm nơi này nhiều trăm năm để Vương Lâm cảm ngộ cấm chế bổn nguyên.","detail":"Cấm trận cốc là một trong ba nơi tạo hóa Huyền La chuẩn bị cho Vương Lâm trong lãnh địa Đạo Cổ. Các ký hiệu trên vách đá chứa trận pháp cấm chế, khiến nơi này trở thành chỗ Vương Lâm ngồi cảm ngộ ba tháng về cấm chế bổn nguyên dưới sự hộ pháp của Huyền La.","nguon":["@c1909"]},{"id":"tieng-chuong-tren-dinh-co-dao-son","name":"Tiếng chuông trên đỉnh Cổ Đạo Sơn","cn":"","loai":"than-thong","loaiLabel":"Thần thông/uy áp chuông","phamCap":"Không rõ","hePhai":"Cổ Đạo Sơn","soHuu":[],"blurb":"Tiếng chuông phát ra từ các chuông treo trên xích sắt quanh tháp chín tầng ở đỉnh Cổ Đạo Sơn. Âm thanh này khiến tâm thần thông suốt và thúc sức mạnh Cổ Tộc vận chuyển, nhưng lại áp chế dữ dội bổn nguyên cùng tu vi Tiên Tộc của Vương Lâm.","detail":"Khi Vương Lâm theo Huyền La lên đỉnh Cổ Đạo Sơn, tiếng chuông quanh tháp chín tầng vừa có tác dụng khu trừ tạp niệm, vừa làm sức mạnh Cổ Tộc trong cơ thể hắn vận chuyển nhanh hơn. Đồng thời, nó áp chế bổn nguyên và tu vi Tiên Tộc của hắn đến mức thân thể như gánh núi lớn; sau ba ngày, tiếng chuông như muốn hòa tan phần bổn nguyên và tu vi ấy, ép Hồn Huyết trong cơ thể hắn hòa vào huyết mạch toàn thân.","nguon":["@c1909"]},{"id":"linh-am-co-dao-son","name":"Linh âm Cổ Đạo Sơn","cn":"","loai":"than-thong","loaiLabel":"Thần thông âm lực","phamCap":"","hePhai":"Cổ Tộc","soHuu":["Cổ Đạo Đại Thiên Tôn"],"blurb":"Tiếng chuông gió quanh tháp cao trên Cổ Đạo Sơn hóa thành âm lực công kích tâm thần và tu vi bổn nguyên của Vương Lâm.","detail":"Linh âm này được dùng để áp chế Vương Lâm, nhằm đánh tan tu vi bổn nguyên Tiên Tộc trong thân thể hắn. Dưới sức ép kéo dài, Vương Lâm nhiều lần thổ huyết và bị đẩy lùi khỏi các bậc đá, nhưng sau đó tự áp chế linh âm trong cơ thể để phản kháng.","nguon":["@c1910"]},{"id":"dai-thien-ton-chi-duong-nua-trang-nua-den-cua-vuong-lam","name":"Đại Thiên Tôn chi dương nửa trắng nửa đen của Vương Lâm","cn":"","loai":"khac","loaiLabel":"Dị tượng chiến lực","phamCap":"Có thể so với Đại Thiên Tôn","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Dị tượng Đại Thiên Tôn chi dương hiện sau lưng Vương Lâm trong trạng thái nửa trắng nửa đen, bộc phát chiến lực cực mạnh.","detail":"Khi bị đẩy xuống bậc thang cuối của Cổ Đạo Sơn, Vương Lâm áp chế linh âm trong cơ thể, tóc chuyển thành nửa trắng nửa đen và sau lưng hiện Đại Thiên Tôn chi dương cùng hai màu tương ứng. Trạng thái này khiến lực lượng của hắn tăng vọt tới mức có thể so với Đại Thiên Tôn.","nguon":["@c1910"]},{"id":"tran-phap-dong-phu-trong-mong","name":"Trận pháp động phủ trong mộng","cn":"","aliases":[],"loai":"khac","loaiLabel":"Trận pháp","phamCap":"không rõ","hePhai":"","soHuu":["Nữ tử trong mộng"],"blurb":"Trận pháp được nữ tử trong mộng liên tục biến hóa để chống lại nhiều tu sĩ bên ngoài động phủ. Nó bảo vệ nơi nam tử trong mộng đang kết đan.","detail":"Trong chuỗi ký ức mơ hồ, nữ tử trong mộng dùng trận pháp này để phòng hộ động phủ giữa lúc nhiều tu sĩ muốn phá vào. Công dụng được thể hiện là chống cự và kéo dài thời gian bảo vệ nam tử đang kết đan.","congNang":["Phòng hộ động phủ và chống lại nhiều tu sĩ đang muốn phá vào @c1911"],"nguoiTu":[{"ten":"Nữ tử trong mộng","tuChuong":"@c1911","tangDatToi":"","trangThai":"thi triển"}],"tabs":{"tienTrinh":[{"chuong":"@c1911","loai":"thi triển","importance":"normal","giaiDoan":"Bảo vệ động phủ trong mộng","text":"Nữ tử trong mộng liên tục biến hóa trận pháp để chống lại các tu sĩ vây phá động phủ.","anchor":"không ngừng biến hóa trận pháp chống cự"}]},"dinhDanh":"goc","capNhatToi":"@c1911","nguon":["@c1911"]},{"id":"chuong-hac-bach-cua-vuong-lam","name":"Chưởng hắc bạch của Vương Lâm","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Tiên Cổ","soHuu":["Vương Lâm"],"blurb":"Thần thông Vương Lâm dùng trên Cổ Đạo Sơn, ngưng tụ hào quang hắc bạch ở tay phải để đánh tan giao long do bậc thang hóa thành.","detail":"Khi bậc thang một trăm hóa thành giao long đen lao tới, Vương Lâm ngưng tụ hào quang hắc bạch trên tay phải, lòng bàn tay trắng và lưng bàn tay đen, rồi đánh một chưởng phá tan đầu giao long.","congNang":["Đánh tan giao long cản đường trên Cổ Đạo Sơn @c1912"],"uyLuc":"Một chưởng phá đầu giao long do bậc thang hóa thành, nhưng khiến Vương Lâm chịu phản chấn nặng.","trangThai":"đã thi triển","capNhatToi":"@c1912","tabs":{"tienTrinh":[{"chuong":"@c1912","loai":"thi triển","importance":"normal","giaiDoan":"Bậc một trăm Cổ Đạo Sơn","text":"Vương Lâm ngưng tụ hào quang hắc bạch trên tay phải và dùng một chưởng đánh tan giao long do bậc thang hóa thành.","anchor":"từng trận hào quang hắc bạch ngưng tụ ở trên tay phải Vương Lâm"}]},"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1912","tangDatToi":"Đã thi triển","trangThai":"đang dùng"}],"nguon":["@c1912"]},{"id":"dung-hop-tien-co-cua-vuong-lam","name":"Dung hợp Tiên Cổ của Vương Lâm","cn":"","aliases":[],"loai":"cong-phap","loaiLabel":"Tu luyện","phamCap":"Không rõ","hePhai":"Tiên Cổ","soHuu":["Vương Lâm"],"blurb":"Quá trình dung hợp tu vi Tiên Tộc dựa vào bổn nguyên với sức mạnh Cổ Tộc dựa vào huyết mạch trong cơ thể Vương Lâm. Cổ Đạo Sơn trở thành môi trường uy áp đặc biệt thúc ép sự dung hợp này.","detail":"Trên Cổ Đạo Sơn, uy áp khổng lồ của ngọn núi đã cưỡng ép hai hệ lực lượng vốn khó hợp nhất trong cơ thể Vương Lâm — tu vi Tiên Tộc và sức mạnh Cổ Tộc — bắt đầu xuất hiện dấu hiệu dung hợp. Vương Lâm nhận ra rằng uy áp nơi đây chính là điều kiện tu luyện tốt nhất để thúc đẩy quá trình hợp nhất hai nguồn sức mạnh này.","thuocTinh":"Tiên Cổ","yeuCau":"Có tu vi Tiên Tộc dựa vào bổn nguyên và sức mạnh Cổ Tộc dựa vào huyết mạch.","congNang":["Dung hợp tu vi Tiên Tộc và sức mạnh Cổ Tộc trong cơ thể Vương Lâm @c1912"],"dacDiem":"Cần uy áp mạnh như Cổ Đạo Sơn để cưỡng ép hai hệ lực lượng vốn khó hợp nhất.","trangThai":"đang tu luyện","capNhatToi":"@c1912","tabs":{"tienTrinh":[{"chuong":"@c1912","loai":"xuất hiện","importance":"major","giaiDoan":"Cổ Đạo Sơn","text":"Uy áp Cổ Đạo Sơn khiến tu vi Tiên Tộc và sức mạnh Cổ Tộc trong cơ thể Vương Lâm xuất hiện dấu hiệu dung hợp. Vương Lâm xác định đây là cơ hội tu luyện then chốt và quyết định tiếp tục leo núi.","anchor":"tu vi của Tiên Tộc và sức mạnh của Cổ Tộc như đã có dấu hiệu dung hợp"}]},"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1912","tangDatToi":"Có dấu hiệu dung hợp","trangThai":"đang tu luyện"}],"nguon":["@c1912"]},{"id":"thieu-dot-dai-thien-ton-chi-duong","name":"Thiêu đốt Đại Thiên Tôn chi dương","cn":"","aliases":[],"loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Đại Thiên Tôn chi lực","hePhai":"Đại Thiên Tôn","soHuu":["Vương Lâm"],"blurb":"Cách Vương Lâm co rút và hấp thu Đại Thiên Tôn chi dương phía sau để đổi lấy sức mạnh leo Cổ Đạo Sơn. Bí thuật này giúp hắn vượt từ bậc một trăm năm mươi lên bậc hai trăm.","detail":"Khi bị uy áp sau bậc một trăm ép dừng ở bậc một trăm năm mươi, Vương Lâm thu nhỏ hình ảnh mặt trời Đại Thiên Tôn phía sau, để lực lượng dung nhập thân thể rồi liên tiếp bước lên các bậc cao hơn.","congNang":["Đổi lực lượng trong Đại Thiên Tôn chi dương lấy khí lực để leo tới bậc hai trăm @c1912"],"uyLuc":"Giúp Vương Lâm vượt thêm năm mươi bậc dưới uy áp Cổ Đạo Sơn.","trangThai":"đã thi triển","capNhatToi":"@c1912","tabs":{"tienTrinh":[{"chuong":"@c1912","loai":"thi triển","importance":"normal","giaiDoan":"Bậc một trăm năm mươi tới hai trăm","text":"Vương Lâm thiêu đốt Đại Thiên Tôn chi dương sau lưng để đổi lấy sức mạnh, nhờ đó bước lên bậc thứ hai trăm.","anchor":"Thiêu đốt Đại Thiên Tôn chi dương, đổi lấy khí lực để bước lên bậc thứ hai trăm"}]},"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1912","tangDatToi":"Đã thi triển","trangThai":"đang dùng"}],"nguon":["@c1912"]},{"id":"mot-chi-cua-nguoi-ao-xam","name":"Một chỉ của người áo xám","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Sánh Đại Thiên Tôn","hePhai":"Không rõ","soHuu":["Người áo xám trên cột phía bắc"],"blurb":"Thần thông người áo xám trên cột phía bắc dùng để công kích Vương Lâm tại bậc hai trăm Cổ Đạo Sơn. Một chỉ này khiến thiên địa biến hóa và được Vương Lâm cảm nhận có uy lực sánh Đại Thiên Tôn.","detail":"Người áo xám xuất hiện trước Vương Lâm và điểm một chỉ về phía mi tâm hắn. Uy lực của một chỉ tạo nguy cơ hình thần câu diệt, buộc Vương Lâm dốc toàn lực bằng bổn nguyên, hư ảnh Tiên Cổ và quyền sát lục lôi đình để phá giải.","congNang":["Công kích mi tâm đối thủ, gây biến hóa thiên địa và áp lực sánh Đại Thiên Tôn @c1912"],"uyLuc":"Được Vương Lâm cảm nhận có thể so với Đại Thiên Tôn.","trangThai":"đã thi triển","capNhatToi":"@c1912","tabs":{"tienTrinh":[{"chuong":"@c1912","loai":"thi triển","importance":"normal","giaiDoan":"Bậc hai trăm Cổ Đạo Sơn","text":"Người áo xám điểm một chỉ vào mi tâm Vương Lâm, khiến thiên địa biến hóa và uy hiếp hình thần câu diệt.","anchor":"Một chỉ này hạ xuống, thiên địa biến hóa, dường như trong chớp mắt"}]},"nguoiTu":[{"ten":"Người áo xám trên cột phía bắc","tuChuong":"@c1912","tangDatToi":"Đã thi triển","trangThai":"đang dùng"}],"nguon":["@c1912"]},{"id":"quyen-hop-nhat-tien-co-sat-loi-cua-vuong-lam","name":"Quyền hợp nhất Tiên Cổ sát lôi của Vương Lâm","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Sơ bộ Đại Thiên Tôn lực","hePhai":"Tiên Cổ","soHuu":["Vương Lâm"],"blurb":"Một quyền Vương Lâm dùng để chống lại một chỉ của người áo xám trên Cổ Đạo Sơn. Quyền này hợp lực lượng Đại Thiên Tôn chi dương đã hấp thu, bổn nguyên, hư ảnh Đạo Cổ, Cổ Thần, Cổ Yêu, Cổ Ma và sát lục lôi đình.","detail":"Trong nguy cơ bị một chỉ đánh vào mi tâm, Vương Lâm bộc phát lực lượng đã hấp thu, vận chuyển bổn nguyên và gọi ra nhiều tầng hư ảnh cùng quyền sát lục lôi đình. Một quyền này phá vỡ một chỉ của người áo xám, giúp hắn đứng vững ở bậc hai trăm dù trọng thương.","congNang":["Phá một chỉ có uy lực sánh Đại Thiên Tôn của người áo xám @c1912"],"uyLuc":"Có thể phá thần thông Đại Thiên Tôn cấp trong trạng thái Vương Lâm dốc toàn lực.","dacDiem":"Kết hợp hư ảnh Đạo Cổ, Cổ Thần, Cổ Yêu, Cổ Ma với lực sát lục lôi đình và bổn nguyên.","trangThai":"đã thi triển","capNhatToi":"@c1912","tabs":{"tienTrinh":[{"chuong":"@c1912","loai":"thi triển","importance":"normal","giaiDoan":"Bậc hai trăm Cổ Đạo Sơn","text":"Vương Lâm dốc toàn lực thi triển một quyền hợp nhất nhiều tầng lực lượng Tiên Cổ và sát lục lôi đình, phá vỡ một chỉ của người áo xám.","anchor":"Một quyền này xuất ra, ở phía Vương Lâm xuất hiện hư ảnh của Đạo Cổ"}]},"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1912","tangDatToi":"Đã thi triển","trangThai":"đang dùng"}],"nguon":["@c1912"]},{"id":"kim-thien-hac-dia","name":"Kim Thiên Hắc Địa","cn":"","loai":"khac","loaiLabel":"Tướng dị tượng","phamCap":"Đệ nhất tượng trong Cửu Khúc Tam Tướng","hePhai":"Cửu Khúc Tam Tướng","soHuu":["Vương Lâm"],"blurb":"Đệ nhất tượng của Cửu Khúc Tam Tướng, xuất hiện khi Vương Lâm dung hợp được một tia Tiên Cổ lực. Dị tượng làm trời hóa vàng kim, đất hóa đen trong phạm vi rộng quanh Cổ Đạo Sơn.","detail":"Kim Thiên Hắc Địa hiện ra sau khi Vương Lâm bước tới bậc hai trăm mười một và dưới uy áp sinh ra một tia lực lượng mới vừa là tiên vừa là cổ. Bầu trời trong phạm vi mười vạn dặm chuyển thành màu vàng kim, mặt đất hóa đen thẫm; Huyền La nhận ra đây là đệ nhất tượng trong Cửu Khúc Tam Tướng.","nguon":["@c1913"]},{"id":"thuong-khung-phong-khuc","name":"Thương Khung Phong Khúc","cn":"","loai":"khac","loaiLabel":"Khúc dị tượng âm thanh","phamCap":"Cửu Khúc đệ nhất âm","hePhai":"Cửu Khúc Tam Tướng","soHuu":["Vương Lâm"],"blurb":"Khúc thứ nhất trong Cửu Khúc, vang lên khi Vương Lâm đứng vững trên bậc hai trăm hai mươi. Âm gió xuất hiện trong cảnh Kim Thiên Hắc Địa dù không thấy nguồn gió rõ ràng.","detail":"Thương Khung Phong Khúc vang lên sau khi Vương Lâm chịu uy áp khiến thân thể nhiều lần sụp đổ rồi tái ngưng tụ, cuối cùng đứng trên bậc hai trăm hai mươi. Đây là Cửu Khúc đệ nhất âm, khiến những người quan sát trên Cổ Đạo Sơn, gồm Huyền La và thân ảnh trên đỉnh tháp, đều nhận ra sự xuất hiện tiếp theo của hệ dị tượng Cửu Khúc Tam Tướng.","nguon":["@c1913"]},{"id":"thien-dao-loi-am","name":"Thiên Đạo Lôi Âm","cn":"","loai":"khac","loaiLabel":"Khúc dị tượng âm thanh","phamCap":"Khúc thứ hai trong Cửu Khúc","hePhai":"Cửu Khúc Tam Tướng","soHuu":["Vương Lâm"],"blurb":"Khúc thứ hai trong Cửu Khúc, vang lên như tiếng sấm khi Vương Lâm lên bậc hai trăm ba mươi. Âm lôi hòa với Phong Khúc, làm dị tượng âm thanh tiếp tục mở rộng.","detail":"Thiên Đạo Lôi Âm xuất hiện khi Vương Lâm lên tới bậc hai trăm ba mươi trên Cổ Đạo Sơn. Nó là khúc thứ hai trong Cửu Khúc, hòa cùng Thương Khung Phong Khúc trước đó, mở đầu cho chuỗi âm gió, sấm, mây và các âm khác lần lượt cộng hưởng quanh quá trình Vương Lâm dung hợp Tiên Cổ.","nguon":["@c1913"]},{"id":"pham-tran-van-dich","name":"Phàm Trần Vân Địch","cn":"","loai":"khac","loaiLabel":"Khúc dị tượng âm thanh","phamCap":"Khúc thứ ba trong Cửu Khúc","hePhai":"Cửu Khúc Tam Tướng","soHuu":["Vương Lâm"],"blurb":"Khúc thứ ba trong Cửu Khúc, là tiếng sáo từ mây trắng trên bầu trời vàng. Khi xuất hiện ở bậc hai trăm bốn mươi, nó hòa với phong lôi và giúp thương thế Vương Lâm phục hồi.","detail":"Phàm Trần Vân Địch vang lên khi Vương Lâm bước lên bậc hai trăm bốn mươi. Tiếng sáo từ mây trắng hòa cùng Thương Khung Phong Khúc và Thiên Đạo Lôi Âm thành một khúc nhạc truyền vào lòng Vương Lâm, sưởi ấm Nguyên Thần và linh hồn, khiến thương thế trong ngoài thân thể hắn được chữa lành trong quá trình chịu uy áp.","nguon":["@c1913"]},{"id":"van-vat-nhuan-vu","name":"Vạn Vật Nhuận Vũ","cn":"","loai":"khac","loaiLabel":"Khúc dị tượng âm thanh","phamCap":"Khúc thứ tư trong Cửu Khúc","hePhai":"Cửu Khúc Tam Tướng","soHuu":["Vương Lâm"],"blurb":"Khúc mưa rơi xuất hiện khi Vương Lâm lên bậc hai trăm năm mươi. Âm mưa hòa với Vân Địch, gợi ý vạn vật được tưới nhuần và hồi sinh.","detail":"Vạn Vật Nhuận Vũ là khúc thứ tư trong chuỗi Cửu Khúc hiện trên người Vương Lâm. Khi hắn lên bậc hai trăm năm mươi, tiếng mưa rơi vang lên và dung nhập cùng các âm trước đó, khiến khúc nhạc dị tượng có thêm ý vị sinh cơ, như vạn vật được mưa tưới mà hồi sinh.","nguon":["@c1913"]},{"id":"khuc-khong-trung","name":"Khúc không trung","cn":"","loai":"khac","loaiLabel":"Khúc dị tượng âm thanh","phamCap":"Khúc thứ năm trong Cửu Khúc","hePhai":"Cửu Khúc Tam Tướng","soHuu":["Vương Lâm"],"blurb":"Khúc thứ năm phát ra từ không trung ở bậc hai trăm sáu mươi. Âm ngân nga này hòa cùng bốn khúc trước và khiến Tiên Cổ lực trong người Vương Lâm bắt đầu có dấu hiệu vận chuyển.","detail":"Khúc không trung, còn được mô tả như một tiếng ngân nga mơ hồ từ không trung vốn không có tiếng động, xuất hiện khi Vương Lâm lên bậc hai trăm sáu mươi. Sau khi hòa vào bốn khúc đã có, nó làm Tiên Cổ lực trong cơ thể Vương Lâm bắt đầu vận chuyển chậm, đồng thời liên quan tới dấu hiệu hòa tan của Hồn Huyết Cổ Tổ trong người hắn.","nguon":["@c1913"]},{"id":"khuc-nhac-dai-dia","name":"Khúc nhạc đại địa","cn":"","loai":"khac","loaiLabel":"Khúc dị tượng âm thanh","phamCap":"Khúc thứ sáu trong Cửu Khúc","hePhai":"Cửu Khúc Tam Tướng","soHuu":["Vương Lâm"],"blurb":"Khúc thứ sáu phát ra từ mặt đất màu đen khi Vương Lâm lên bậc hai trăm tám mươi. Âm điệu mang vẻ thê lương như táng âm, tạo thành lục khúc nhị tướng.","detail":"Khúc nhạc đại địa, còn được mô tả là táng âm đại địa, xuất hiện khi sức mạnh Cổ Tộc trong cơ thể Vương Lâm hòa tan ở bậc hai trăm tám mươi. Từ mặt đất đen vang lên âm thanh đau thương mang ý chôn cất người chết, khiến dị tượng trên người hắn tiến thêm thành lục khúc nhị tướng.","nguon":["@c1913"]},{"id":"nhuoc-the-am","name":"Nhược Thể Âm","cn":"","loai":"khac","loaiLabel":"Khúc thân thể","phamCap":"Khúc thứ bảy trong Cửu Khúc","hePhai":"Cửu Khúc Tam Tướng","soHuu":["Vương Lâm"],"blurb":"Khúc thứ bảy trong Cửu Khúc, phát ra từ chính thân thể Vương Lâm. Chỉ hắn nghe thấy âm này khi lên bậc hai trăm chín mươi.","detail":"Nhược Thể Âm xuất hiện ở bậc hai trăm chín mươi, không đến từ trời đất bên ngoài mà từ thân thể Vương Lâm. Âm thanh này phát ra từ cử động, hô hấp và cả lông tóc trên người hắn, hòa với các âm giữa thiên địa và trở thành khúc thứ bảy trong Cửu Khúc Tam Tướng đang hiển hiện trên hắn.","nguon":["@c1913"]},{"id":"ngu-tang-khuc","name":"Ngũ Tạng Khúc","cn":"","loai":"khac","loaiLabel":"Khúc thân thể","phamCap":"Khúc thứ tám trong Cửu Khúc","hePhai":"Cửu Khúc Tam Tướng","soHuu":["Vương Lâm"],"blurb":"Khúc thứ tám bộc phát từ lục phủ ngũ tạng của Vương Lâm khi hai người áo xám hợp thể tấn công. Nó thúc đẩy Cổ lực và bản nguyên lực lần đầu dung hợp hoàn toàn lấy thân thể hắn làm trung tâm.","detail":"Ngũ Tạng Khúc bộc phát đúng lúc Vương Lâm đứng trên bậc ba trăm và bị người áo xám hợp thể đánh tới. Tiếng phổi co bóp, tim đập, lá lách rung động, gan và thận vận chuyển hòa thành khúc thứ tám, khiến Cổ lực và bản nguyên lực trong cơ thể hắn tản ra rồi ngưng tụ, lần đầu hoàn toàn dung hợp lấy thân thể Vương Lâm làm trung tâm. Sau đó Tiên Cổ lực vận chuyển trọn một vòng trong nháy mắt và hóa thành tiếng quát đẩy lui công kích.","nguon":["@c1913"]},{"id":"tien-co-luc-dung-hop-cua-vuong-lam","name":"Tiên Cổ lực dung hợp của Vương Lâm","cn":"","loai":"khac","loaiLabel":"Lực lượng dung hợp","phamCap":"","hePhai":"Tiên Cổ dung hợp","soHuu":["Vương Lâm"],"blurb":"Lực lượng mới sinh ra từ sự dung hợp tu vi bổn nguyên Tiên Tộc và lực lượng Cổ Tộc trong cơ thể Vương Lâm. Nó không thuần tiên cũng không thuần cổ, mà thuộc về chính hắn.","detail":"Tiên Cổ lực dung hợp của Vương Lâm lần đầu lộ rõ khi hắn bước qua bậc hai trăm mười một dưới uy áp Cổ Đạo Sơn, tạo ra một tia lực lượng vừa là tiên lực vừa là cổ lực nhưng không hoàn toàn thuộc về bên nào. Về cuối chương, dưới tác động của Ngũ Tạng Khúc, bản nguyên lực và Cổ lực trong cơ thể hắn lần đầu dung hợp hoàn toàn, hoàn thành một vòng vận chuyển tức thời và trở thành sức mạnh để hắn quát lui đòn công kích của người áo xám hợp thể.","nguon":["@c1913"]},{"id":"tien-co-dung-hop","name":"Tiên Cổ dung hợp","cn":"","aliases":["Tiên Cổ lực dung hợp"],"loai":"than-thong","loaiLabel":"Lực lượng dung hợp","phamCap":"chưa rõ","hePhai":"Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Tiên Cổ dung hợp là trạng thái dung hợp bản nguyên lực (lực Tiên) và Cổ Tộc lực trong cơ thể Vương Lâm, tạo ra một loại lực không phải tiên cũng không phải cổ, có thể bộc phát uy áp sánh với Cổ Đạo Sơn trong thời gian ngắn. Hiện trạng thái này mới ở giai đoạn sơ khai, vòng tuần hoàn thứ hai vận chuyển rất chậm nhưng cho thấy tiềm năng tiếp tục trưởng thành.","detail":"Tại Cổ Đạo Sơn, bên trong cơ thể Vương Lâm xuất hiện một lực lượng đặc thù — không phải tiên lực, cũng không phải Cổ Tộc lực — mà là sản phẩm dung hợp của cả hai. Khi Vương Lâm động niệm, lực này bộc phát ra bên ngoài, phát ra uy áp cực mạnh sánh ngang với Cổ Đạo Sơn. Sau khi va chạm với bàn tay của Cổ Đạo Đại Thiên Tôn, lực dung hợp tuy bị chia lìa nhưng không triệt tiêu hoàn toàn, mà bắt đầu vận hành vòng tuần hoàn thứ hai — dù tốc độ rất chậm. Điều này cho thấy Tiên Cổ dung hợp có khả năng tự phục hồi và tiếp tục phát triển, hiện vẫn đang ở giai đoạn dung hợp ngắn ngủi, chưa ổn định.","thuocTinh":"Tiên Cổ dung hợp","uyLuc":"Có thể tạo uy áp sánh với Cổ Đạo Sơn trong thời gian ngắn khi Vương Lâm động niệm.","dacDiem":"Hiện mới dung hợp ngắn ngủi, vòng tuần hoàn thứ hai vận chuyển rất chậm, cho thấy trạng thái này vẫn đang ở giai đoạn sơ khai và chưa ổn định.","congNang":["Dung hợp bản nguyên lực và Cổ Tộc lực thành một loại lực bộc phát ngắn ngủi, không thuộc tiên cũng không thuộc cổ @c1914"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1914","tangDatToi":"có thể động niệm dung hợp ngắn ngủi","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1914","loai":"hé lộ tầng-chiêu","importance":"major","giaiDoan":"Vòng tuần hoàn thứ hai","text":"Tiên Cổ dung hợp trong cơ thể Vương Lâm bộc phát uy áp sánh Cổ Đạo Sơn, sau va chạm vẫn tiếp tục vận chuyển vòng tuần hoàn thứ hai.","anchor":"lực lượng không phải tiên, không phải cổ vận chuyển tuần hoàn trong người Vương Lâm"}]},"capNhatToi":"@c1914","nguon":["@c1914"]},{"id":"mot-chi-cua-co-to","name":"Một chỉ của Cổ Tổ","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Cổ tộc","soHuu":["Cổ Tổ","Vương Lâm"],"blurb":"Thần thông một chỉ của Cổ Tổ, từng hiện trong ký ức được Vương Lâm kích phát từ ngọc giản và Hồn Huyết.","detail":"Khi Cổ Tổ giơ tay điểm một chỉ, thiên địa trong phạm vi mười vạn dặm quanh đàn hung thú như bị chia cắt rồi ép lại. Uy lực của một chỉ này nghiền nát toàn bộ đàn mãnh thú, kể cả con dẫn đầu có khí tức gần tới Đại Thiên Tôn, khiến Vương Lâm sau khi xem ký ức phải tán thưởng.","nguon":["@c1915"]},{"id":"cam-che-dong-phu-duoi-nha-go","name":"Cấm chế động phủ dưới nhà gỗ","cn":"","loai":"khac","loaiLabel":"Trận pháp/cấm chế","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Hệ cấm chế do Vương Lâm bố trí quanh động phủ bí mật dưới nhà gỗ để ẩn giấu và phòng hộ nơi tu luyện.","detail":"Cấm chế này lấy sức mạnh dung hợp không tiên không cổ trong cơ thể Vương Lâm làm nền. Nhờ vậy, ngay cả Dược Thiên Tôn cũng khó xông vào, còn Đại Thiên Tôn nếu không xem xét kỹ cũng khó phát hiện động phủ bên dưới.","nguon":["@c1915"]},{"id":"tran-phap-dich-chuyen-trong-nha-go","name":"Trận pháp dịch chuyển trong nhà gỗ","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Trận pháp trong nhà gỗ dùng để đưa Vương Lâm xuống động phủ bí mật sâu dưới lòng đất.","detail":"Vương Lâm vung tay áo mở trận pháp, ánh sáng của trận không khuếch tán ra ngoài. Hắn bước vào trận pháp rồi biến mất, dịch chuyển xuống động phủ nằm sâu hàng vạn trượng bên dưới.","nguon":["@c1915"]},{"id":"ngan-muc-cua-vuong-lam","name":"Ngân mục của Vương Lâm","cn":"","loai":"than-thong","loaiLabel":"Thần thông/trạng thái mắt","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Trạng thái mắt bạc của Vương Lâm, được dùng để áp chế khí xám Trớ Thuật và nhìn thấu ngọc giản một chỉ của Cổ Tổ.","detail":"Khi rút một tia khí xám Trớ Thuật khỏi linh hồn Tiên Hoàng, Vương Lâm khiến ngân quang xuất hiện trong hai mắt để áp chế hư ảnh ác quỷ do khí xám hóa thành. Sau đó hắn tiếp tục dùng đôi mắt bạc nhìn vào ngọc giản Kế Đô tặng, khiến các mảnh ký ức từ Hồn Huyết nối liền và hiện ra cảnh Cổ Tổ thi triển một chỉ.","nguon":["@c1915"]},{"id":"uy-ap-sat-khi-cua-vuong-lam","name":"Uy áp sát khí của Vương Lâm","cn":"","loai":"than-thong","loaiLabel":"Thần thông / uy áp","phamCap":"Chưa rõ","hePhai":"Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Uy áp và sát khí được Vương Lâm bộc phát trong chớp mắt tại đại yến Đạo Cổ. Chỉ một ánh mắt cùng hồng quang sát khí đã ép Bất Diệt Tướng tương đương Dược Thiên Tôn không thể đứng lên.","detail":"Khi một Bất Diệt Tướng trong hắc khí định đứng dậy ngăn Vương Lâm, hắn lạnh lùng nhìn lại và tỏa uy áp kinh người kèm sát khí. Đối phương lập tức run rẩy ngồi xuống, trong tâm thần còn sinh ra cảm giác bị Vương Lâm sát phạt vô số lần.","thuocTinh":"Sát khí, uy áp","uyLuc":"Ép Bất Diệt Tướng tương đương Dược Thiên Tôn không thể đứng nổi.","dacDiem":"Bộc phát cực nhanh, đánh thẳng vào khí thế và tâm thần đối thủ.","nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1918","tangDatToi":"Thi triển trong đại yến Đạo Cổ","trangThai":"dang-dung"}],"congNang":["Tỏa uy áp và sát khí trong chớp mắt để trấn áp đối thủ đang định ra tay @c1918","Gây cảm giác bị sát phạt liên tục trong tâm thần đối phương @c1918"],"tabs":{"tienTrinh":[{"chuong":"@c1918","loai":"thi triển","importance":"normal","giaiDoan":"Trấn áp Bất Diệt Tướng","text":"Vương Lâm dùng ánh mắt cùng uy áp sát khí làm Bất Diệt Tướng đang định đứng lên lập tức run rẩy, không thể tiếp tục ngăn cản hắn.","anchor":"lập tức có một uy áp kinh người từ trên người Vương Lâm bỗng nhiên tản ra"}]},"dinhDanh":"goc","capNhatToi":"@c1918","nguon":["@c1918"]},{"id":"ngu-hanh-ban-nguyen-chan-than","name":"Ngũ hành bản nguyên chân thân","cn":"","aliases":[],"loai":"khac","loaiLabel":"Chân thân bản nguyên","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Ngũ hành bản nguyên chân thân là trạng thái hợp nhất các chân thân ngũ hành của Vương Lâm, hoàn thiện khi kim bản nguyên chân thân bước ra đầy đủ.","detail":"Trong cơn cuồng nộ tại Đạo Cổ Điện, kim bản nguyên chân thân của Vương Lâm hoàn toàn thành hình, hợp cùng các chân thân ngũ hành còn lại để tạo thành ngũ hành chân thân đầy đủ. Khi dung nhập vào bản thể, trạng thái này trực tiếp đẩy tu vi Vương Lâm từ Không Kiếp hậu kỳ lên Không Kiếp đại viên mãn.","nguon":["@c1919"]},{"id":"dai-tran-dao-co-dien","name":"Đại trận Đạo Cổ Điện","cn":"","aliases":[],"loai":"khac","loaiLabel":"Trận pháp cấm chế","phamCap":"","hePhai":"Đạo Cổ Điện","soHuu":["Chín đại cường giả dưới trướng Huyền La"],"blurb":"Đại trận Đạo Cổ Điện là trận pháp do chín thuộc hạ Huyền La mượn thanh khí Đạo Cổ Điện dựng lên để ngăn Vương Lâm.","detail":"Khi Vương Lâm rời Đạo Cổ Điện lao tới hoàng cung, chín cường giả dưới trướng Huyền La dùng thanh khí mênh mông của Đạo Cổ Điện tạo thành trận pháp cấm chế khổng lồ nhằm phong cản bước chân hắn. Trận này bị Đại Thiên Tôn chi dương của Vương Lâm đánh sập, còn chín người bị chấn văng.","nguon":["@c1919"]},{"id":"man-thanh-khi-phong-ho-hoang-cung","name":"Màn thanh khí phòng hộ hoàng cung","cn":"","aliases":[],"loai":"khac","loaiLabel":"Cấm chế phòng hộ","phamCap":"","hePhai":"Đạo Cổ hoàng cung","soHuu":["Đạo Cổ hoàng cung"],"blurb":"Màn thanh khí phòng hộ hoàng cung là tầng phòng hộ màu xanh xuất hiện khi Dịch Linh Ấn mười ngón của Vương Lâm đánh tới.","detail":"Trước sức ép của Vương Lâm ngoài hoàng cung, màn thanh khí hiện ra để ngăn chưởng ấn mười ngón. Sau va chạm với Dịch Linh Ấn, tầng phòng hộ này lóe sáng dữ dội rồi sụp đổ thành vô số mảnh, mở đường cho huyết vụ và tiếng bước chân của Vương Lâm tràn vào quảng trường.","nguon":["@c1919"]},{"id":"bi-thuat-hon-huyet-hoi-sinh-than-hon","name":"Bí thuật Hồn Huyết hồi sinh thân-hồn","cn":"","aliases":["Bí thuật Hồn Huyết hồi sinh thân hồn"],"loai":"bi-thuat","loaiLabel":"Bí thuật Cổ Tộc","phamCap":"","hePhai":"Cổ Tộc","soHuu":["Vương Lâm"],"blurb":"Bí thuật Hồn Huyết hồi sinh thân-hồn là thuật Vương Lâm thi triển nhờ Hồn Huyết Cổ Tổ để tái tạo thân thể và trả hồn cho người đã bị hắn đánh nát.","detail":"Sau khi Huyền La xuất hiện, Vương Lâm chứng minh mình không thật sự diệt sát tộc nhân Đạo Cổ bằng cách dùng máu bản thân, Hồn Huyết Cổ Tổ và những hồn phách đã được hắn thu giữ để tái tạo thân thể cho mấy vạn người. Bí thuật này chỉ có thể thi triển sau khi có Hồn Huyết, đồng thời làm Huyền La nhận ra sức mạnh gần như thần tích của truyền thuyết Hồn Huyết Cổ Tổ.","nguon":["@c1919"]},{"id":"dai-cam-cua-co-toc","name":"Đại cấm của Cổ Tộc","cn":"","aliases":["Đại cấm Cổ Tộc"],"loai":"khac","loaiLabel":"Cấm chế phòng hộ","phamCap":"","hePhai":"Cổ Tộc","soHuu":["Phụ thân Đạo Cổ hoàng tôn"],"blurb":"Đại cấm của Cổ Tộc là cấm chế phòng hộ được phụ thân Đạo Cổ hoàng tôn mở bằng huyết mạch để ngăn Đại Thiên Tôn chi dương.","detail":"Khi Đại Thiên Tôn chi dương của Vương Lâm giáng xuống quảng trường hoàng cung, phụ thân Đạo Cổ hoàng tôn dẫn gần ngàn cường giả phòng hộ và dùng huyết mạch mở đại cấm Cổ Tộc. Tầng sáng này tạm thời che chở khu vực phía sau, nhưng sau một nhịp vẫn bị phá, khiến lão già hoàng bào trọng thương và mất cánh tay phải.","nguon":["@c1919"]},{"id":"tu-an-to-quyet-dong-than-toa","name":"Tử Ấn Tổ Quyết Đồng Thần Tỏa","cn":"","aliases":[],"loai":"bi-thuat","loaiLabel":"Thuật ấn khóa sinh tử","phamCap":"","hePhai":"Hoàng tộc Đạo Cổ","soHuu":["Đạo Cổ hoàng tôn","Tống Trí"],"blurb":"Tử Ấn Tổ Quyết Đồng Thần Tỏa là thuật khóa sinh tử Đạo Cổ hoàng tôn đặt lên Tống Trí, khiến nàng bị ràng buộc với hắn.","detail":"Khi Huyền La định đưa Tống Trí đi, tử quang trong người nàng bùng lên, lộ ra Tử Ấn Tổ Quyết Đồng Thần Tỏa. Đạo Cổ hoàng tôn thừa nhận đã đặt khóa này lên nàng, khiến sinh tử của nàng nằm trong tay hắn; nếu tâm thần hắn động, nàng không thể rời quá mười trượng, và nếu hắn chết thì nàng cũng chết. Thuật này được nói là do Cổ Đạo Đại Thiên Tôn truyền cho hoàng tộc, mỗi đời hoàng tôn chỉ thi triển được một lần và chỉ Cổ Đạo Đại Thiên Tôn mới có thể giải trừ.","nguon":["@c1919"]},{"id":"tran-phap-trong-ngon-nui-trong","name":"Trận pháp trong ngọn núi trống","cn":"","aliases":[],"loai":"khac","loaiLabel":"Trận pháp theo dõi và hấp tử khí","phamCap":"","hePhai":"","soHuu":["Thân ảnh mười màu trong ngọn núi trống"],"blurb":"Trận pháp trong ngọn núi trống là trận pháp bí mật của thân ảnh mười màu, dùng để hiển hóa tình hình sinh tử trong Đạo Cổ hoàng cung.","detail":"Bên ngoài Đạo Cổ hoàng cung, thân ảnh mười màu ẩn trong một ngọn núi bị đào rỗng và điều khiển trận pháp khổng lồ. Trận pháp này hiển hóa mô hình hoàng cung bằng các điểm sáng, phân biệt màu trắng là sinh linh, màu đen là tử linh và màu đỏ là Vương Lâm; kẻ điều khiển định lợi dụng sát lục để hút tử linh nhưng phát hiện các điểm đen không bị hấp thu.","nguon":["@c1919"]},{"id":"phong-toa-khong-gian-trong-dao-co-hoang-cung","name":"Phong tỏa không gian trong Đạo Cổ hoàng cung","cn":"","aliases":[],"loai":"khac","loaiLabel":"Cấm chế không gian","phamCap":"","hePhai":"Đạo Cổ hoàng cung","soHuu":["Đạo Cổ hoàng cung"],"blurb":"Phong tỏa không gian trong Đạo Cổ hoàng cung khiến Vương Lâm không thể thuấn di hay thi triển súc địa thành thốn.","detail":"Trong trận xông cung, không gian Đạo Cổ hoàng cung bị phong tỏa, khiến Vương Lâm không thể dùng thuấn di hoặc súc địa thành thốn để trực tiếp tiếp cận mục tiêu. Vì vậy hắn buộc phải giết xuyên qua các vòng vây và tiến từng bước về phía đại điện.","nguon":["@c1919"]},{"id":"tinh-toan-trong-ngoc-gian-cua-lao-to-dai-hon-mon","name":"Tính toán trong ngọc giản của Lão tổ Đại Hồn Môn","cn":"","aliases":["Thuật suy tính trong ngọc giản của Lão tổ Đại Hồn Môn"],"loai":"khac","loaiLabel":"Thuật suy tính chứng cứ","phamCap":"","hePhai":"Đại Hồn Môn","soHuu":["Vương Lâm","Lão tổ Đại Hồn Môn"],"blurb":"Tính toán trong ngọc giản của Lão tổ Đại Hồn Môn giúp Vương Lâm thấy quá trình tàn hồn Lý Mộ Uyển bị lấy đi và dung nhập vào Tống Trí.","detail":"Vương Lâm dùng ngọc giản màu đen do Lão tổ Đại Hồn Môn để lại để suy tính biến cố. Những hình ảnh hiện ra cho thấy tàn hồn Lý Mộ Uyển bị lấy khỏi thiên đạo chúng sinh, chứa trong hạt châu, giao cho nam tử hoàng bào rồi trải qua nhiều lần tuyển phi trước khi dung hợp với Tống Trí. Về sau Vương Lâm còn dùng hình ảnh từ suy tính này làm chứng cứ trước Huyền La và Đạo Cổ hoàng tôn.","nguon":["@c1919"]},{"id":"co-to-cuu-khuc","name":"Cổ Tổ Cửu Khúc","cn":"","aliases":["Cửu Khúc"],"loai":"than-thong","loaiLabel":"Thần thông huyết mạch","phamCap":"không rõ","hePhai":"Cổ Tổ","soHuu":["Vương Lâm"],"blurb":"Cổ Tổ Cửu Khúc là chuỗi chín khúc được vận chuyển bằng Hồn Huyết Cổ Tổ trong cơ thể Vương Lâm, khi thi triển sẽ tràn ngập thiên địa và triệu hiển uy áp Cổ Tổ. Khúc cuối cùng — Huyết Mạch Khúc — phát ra từ Hồn Huyết, khiến mắt Vương Lâm hóa bạc và dẫn tới hư ảnh Cổ Tổ hiện ra phía sau hắn.","detail":"Khi Vương Lâm vận Hồn Huyết, Cổ Tổ Cửu Khúc lần lượt hiện các khúc nối tiếp nhau — trong đó có Thương Khung Phong Khúc, Thiên Đạo Lôi Âm, Phàm Trần Vân Địch, Vạn Vật Nhuận Vũ Khúc, Ngũ Tạng Trấn Minh — và kết thúc bằng Huyết Mạch Khúc. Khúc cuối này phát ra trực tiếp từ Hồn Huyết bên trong cơ thể hắn, làm đôi mắt hóa bạc, đồng thời dẫn tới hư ảnh Cổ Tổ xuất hiện. Uy áp của Cổ Tổ theo đó lan tỏa, đủ sức khiến Cổ Tam Tộc quỳ bái. Vương Lâm thi triển Cổ Tổ Cửu Khúc khi đối đầu với tử quang hộ thân của Đạo Cổ hoàng tôn.","thuocTinh":"huyết mạch Cổ Tổ","uyLuc":"Có thể dẫn động uy áp Cổ Tổ khiến Cổ Tam Tộc quỳ bái khi hư ảnh xuất hiện.","dacDiem":"Gồm nhiều khúc nối tiếp, khúc cuối là Huyết Mạch Khúc phát ra từ Hồn Huyết trong cơ thể Vương Lâm.","chieuTieuBieu":["Huyết Mạch Khúc"],"congNang":["Triệu hiển uy áp Cổ Tổ thông qua vận Hồn Huyết, dẫn tới hư ảnh Cổ Tổ hiện ra phía sau Vương Lâm @c1920"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1920","tangDatToi":"Huyết Mạch Khúc","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1920","loai":"thi triển","importance":"major","giaiDoan":"Huyết Mạch Khúc","text":"Vương Lâm vận Hồn Huyết làm Cổ Tổ Cửu Khúc tràn ngập thiên địa và dùng khúc cuối để hiển hóa uy áp Cổ Tổ.","anchor":"Trong nháy mắt khi Cổ Tổ Cửu Khúc đang tràn ngập thiên địa"}]},"capNhatToi":"@c1920","nguon":["@c1920"]},{"id":"ngu-tang-tran-minh","name":"Ngũ Tạng Trấn Minh","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Khúc trong Cổ Tổ Cửu Khúc","phamCap":"không rõ","hePhai":"Cổ Tổ","soHuu":["Vương Lâm"],"blurb":"Ngũ Tạng Trấn Minh là âm thanh thứ tám trong Cổ Tổ Cửu Khúc được Vương Lâm dẫn động tại Đạo Cổ hoàng cung.","detail":"Khúc thứ tám vang lên thành một thứ âm nhạc không thể dùng âm thanh để hình dung, nối tiếp các khúc trước trong chuỗi Cổ Tổ Cửu Khúc.","phanLoaiPhu":"khúc thứ tám","congNang":["Là khúc thứ tám trong chuỗi Cổ Tổ Cửu Khúc ở @c1920"],"tabs":{"tienTrinh":[{"chuong":"@c1920","loai":"hé lộ tầng-chiêu","importance":"normal","giaiDoan":"khúc thứ tám","text":"Ngũ Tạng Trấn Minh được nêu là âm thanh thứ tám của Cửu Khúc khi Vương Lâm vận thần thông huyết mạch.","anchor":"Âm thanh thứ tám của Cửu Khúc, Ngũ Tạng Trấn Minh"}]},"capNhatToi":"@c1920","nguon":["@c1920"]},{"id":"huyet-mach-khuc","name":"Huyết Mạch Khúc","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Khúc cuối trong Cổ Tổ Cửu Khúc","phamCap":"không rõ","hePhai":"Cổ Tổ","soHuu":["Vương Lâm"],"blurb":"Huyết Mạch Khúc là khúc cuối trong Cổ Tổ Cửu Khúc, phát ra từ Hồn Huyết Cổ Tổ tồn tại bên trong cơ thể Vương Lâm. Khi khúc này vang lên, hư ảnh Cổ Tổ hiện ra phía sau Vương Lâm, khiến tộc nhân Cổ Tam Tộc trong hoàng cung và hoàng thành quỳ bái.","detail":"Huyết Mạch Khúc là khúc nhạc thứ chín — cũng là khúc cuối cùng — của Cổ Tổ Cửu Khúc. Khúc nhạc được kích phát từ Hồn Huyết Cổ Tổ ẩn chứa trong cơ thể Vương Lâm. Khi Huyết Mạch Khúc vang lên, hai mắt Vương Lâm hoàn toàn hóa bạc, hư ảnh Cổ Tổ xuất hiện phía sau hắn. Sự hiện diện này mang theo uy áp huyết mạch của Cổ Tổ, khiến toàn bộ tộc nhân Cổ Tam Tộc — cả trong hoàng cung lẫn ngoài hoàng thành — đều quỳ bái, thể hiện sự chi phối tuyệt đối của huyết mạch Cổ Tổ đối với hậu duệ.","phanLoaiPhu":"khúc cuối","congNang":["Hiển hóa hư ảnh Cổ Tổ phía sau Vương Lâm khi khúc nhạc vang lên @c1920","Phát ra uy áp huyết mạch Cổ Tổ thông qua thân Vương Lâm, bức tộc nhân Cổ Tam Tộc quỳ bái @c1920","Khiến hai mắt Vương Lâm hoàn toàn hóa bạc khi kích phát @c1920"],"tabs":{"tienTrinh":[{"chuong":"@c1920","loai":"hé lộ tầng-chiêu","importance":"major","giaiDoan":"khúc cuối","text":"Huyết Mạch Khúc vang lên từ Hồn Huyết Cổ Tổ trong cơ thể Vương Lâm và dẫn tới hư ảnh Cổ Tổ hiện ra.","anchor":"Khúc cuối cùng này là Huyết Mạch Khúc"}]},"capNhatToi":"@c1920","nguon":["@c1920"],"uyLuc":"Khi Huyết Mạch Khúc vang lên, uy áp huyết mạch Cổ Tổ lan tỏa khiến toàn bộ tộc nhân Cổ Tam Tộc trong hoàng cung và hoàng thành đều quỳ bái, không thể kháng cự.","dacDiem":"Là khúc cuối của Cổ Tổ Cửu Khúc, được kích phát từ Hồn Huyết Cổ Tổ trong cơ thể Vương Lâm; khi vang lên đi kèm biểu hiện đặc trưng là đôi mắt hóa bạc hoàn toàn và hư ảnh Cổ Tổ hiện hình."},{"id":"tran-phap-trong-ngon-nui-hoang","name":"Trận pháp trong ngọn núi hoang","cn":"","aliases":[],"loai":"khac","loaiLabel":"Trận pháp","phamCap":"không rõ","hePhai":"Đạo Cổ nhất mạch","soHuu":["Quốc sư thần bí của Đạo Cổ nhất mạch"],"blurb":"Trận pháp khổng lồ nằm trong lòng ngọn núi hoang ngoài hoàng thành Đạo Cổ. Trận pháp lộ ra khi một chỉ Cổ Tổ của Vương Lâm chém ngọn núi thành hai nửa.","detail":"Trận pháp ở trong ngọn núi hoang hút tử khí của Diệp Đạo sau khi hắn chết. Ở trung tâm trận pháp mơ hồ có một thân ảnh bị Vương Lâm nhận định có liên quan tới quốc sư thần bí của Đạo Cổ nhất mạch.","dinhDanh":"goc","dacDiem":"Khổng lồ, ẩn trong núi hoang và có thân ảnh ở trung tâm.","congNang":["Ẩn giấu thân ảnh nghi là quốc sư thần bí và liên quan tới việc hút tử khí của Diệp Đạo @c1921"],"tabs":{"tienTrinh":[{"chuong":"@c1921","loai":"xuất hiện","importance":"normal","giaiDoan":"Lộ trận pháp","text":"Sau khi ngọn núi hoang bị một chỉ Cổ Tổ chém nứt, bên trong lộ ra trận pháp khổng lồ cùng thân ảnh mơ hồ ở trung tâm.","anchor":"Bên trong đó có một trận pháp khổng lồ"}]},"capNhatToi":"@c1921","nguon":["@c1921"]},{"id":"hon-muoi-van-dai-tran-dao-co-hoang-cung","name":"Hơn mười vạn đại trận Đạo Cổ hoàng cung","cn":"","aliases":[],"loai":"khac","loaiLabel":"Trận pháp","phamCap":"không rõ","hePhai":"Đạo Cổ nhất mạch","soHuu":["Diệp Vi"],"blurb":"Hệ thống hơn mười vạn đại trận trong Đạo Cổ hoàng cung, do Cổ Tổ bố trí, được Diệp Vi dung hợp làm một với bản thân. Nhờ trận pháp này, Diệp Vi có thân thể bất tử trong phạm vi hoàng cung và có thể khai mở tới bảy phần uy lực để uy hiếp đối thủ.","detail":"Đại trận do Cổ Tổ đích thân bố trí bên trong Đạo Cổ hoàng cung, tổng số lượng vượt quá mười vạn trận, tạo thành một hệ thống trận pháp đồ sộ. Diệp Vi đã dung hợp làm một với toàn bộ trận pháp, biến chúng thành lợi thế căn bản khi giao chiến trong phạm vi hoàng cung. Khi đối đầu Vương Lâm tại Đạo Cổ hoàng cung, bà lấy hệ thống trận pháp này làm căn cơ để uy hiếp, tuyên bố rằng trong hoàng cung bà gần như bất tử. Tuy nhiên, cuối cùng bà đã thu trận pháp lại để Vương Lâm rời đi.","nguon":["@c1922"],"nguonGoc":"Cổ Tổ bố trí","congNang":["Giúp Diệp Vi có thân thể bất tử trong phạm vi Đạo Cổ hoàng cung khi đã dung hợp với trận pháp @c1922","Có thể mở ra tới bảy phần uy lực trận pháp để uy hiếp đối thủ @c1922"],"nguoiTu":[{"ten":"Diệp Vi","tuChuong":"@c1922","tangDatToi":"dung hợp với đại trận","trangThai":"đang dung hợp"}],"capNhatToi":"@c1922","tabs":{"tienTrinh":[{"chuong":"@c1922","loai":"xuất hiện","importance":"major","giaiDoan":"Diệp Vi dung hợp đại trận","text":"Diệp Vi dùng hơn mười vạn đại trận do Cổ Tổ bố trí làm căn cơ uy hiếp Vương Lâm trong Đạo Cổ hoàng cung.","anchor":"Nơi này có hơn mười vạn đại trận. Trận pháp này năm đó là do Cổ Tổ bố trí"}]},"dinhDanh":"goc"},{"id":"bat-cuc-dao-cua-tien-to","name":"Bát Cực Đạo của Tiên Tổ","cn":"","aliases":["Bát Cực Đạo"],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"Tiên Tổ","soHuu":["Vương Lâm"],"blurb":"Bát Cực Đạo của Tiên Tổ là thần thông gồm tám đạo cực hạn, trong đó Vương Lâm đã nắm vững sáu đạo (thủy, hỏa, kim, mộc, thổ, Tử Cực Sinh Đạo) sau khi học tại Thiên Tôn Niết. Hắn đem ra triển lộ để đối kháng Diệp Vi cùng đại trận Đạo Cổ hoàng cung, đồng thời đã mơ hồ cảm nhận biến hóa của hai đạo còn lại là Cực Phát Đạo và Cực Khung Đạo.","detail":"Bát Cực Đạo của Tiên Tổ bao gồm tám đạo cực hạn. Vương Lâm học được sáu đạo tại Thiên Tôn Niết, gồm: thủy, hỏa, kim, mộc, thổ và Tử Cực Sinh Đạo. Hai đạo còn lại — Cực Phát Đạo và Cực Khung Đạo — chưa được truyền thừa đầy đủ, nhưng hắn đã mơ hồ cảm nhận được biến hóa của chúng. Tại cuộc đối kháng với Diệp Vi trước đại trận Đạo Cổ hoàng cung, Vương Lâm triển lộ sáu đạo đã nắm giữ nhằm tạo thế đối đầu, qua đó cho thấy phần nào sức mạnh của thần thông này.","nguon":["@c1922"],"congNang":["Triển lộ nhiều đạo cực hạn để tạo thế đối kháng trước cường địch và đại trận, cụ thể là đối đầu Diệp Vi cùng đại trận Đạo Cổ hoàng cung @c1922"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1922","tangDatToi":"lục đạo","trangThai":"đang tu"}],"cacTang":[{"ten":"Lục đạo","moTa":"Vương Lâm đã học được sáu đạo trong Bát Cực Đạo của Tiên Tổ.","chuong":"@c1922"}],"chieuTieuBieu":["Cực Hỏa Đạo","Cực Thủy Đạo","Cực Kim Đạo","Tử Cực Sinh Đạo"],"capNhatToi":"@c1922","tabs":{"tienTrinh":[{"chuong":"@c1922","loai":"hé lộ tầng-chiêu","importance":"major","giaiDoan":"Vương Lâm nắm lục đạo","text":"Vương Lâm triển lộ sáu đạo trong Bát Cực Đạo của Tiên Tổ trước Diệp Vi, đồng thời cho thấy hắn đã mơ hồ chạm tới hai đạo cuối.","anchor":"Bát Cực Đạo của Tiên Tổ, Vương Lâm ở Thiên Tôn Niết đã học được lục đạo"}]},"dinhDanh":"goc","dacDiem":"Thần thông gồm tám đạo cực hạn; sáu đạo đã nắm gồm thủy, hỏa, kim, mộc, thổ và Tử Cực Sinh Đạo, hai đạo Cực Phát Đạo và Cực Khung Đạo chưa truyền thừa đầy đủ nhưng đã mơ hồ cảm nhận biến hóa."},{"id":"cuc-kim-dao","name":"Cực Kim Đạo","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"Bát Cực Đạo của Tiên Tổ","soHuu":["Vương Lâm"],"blurb":"Cực Kim Đạo là một đạo trong Bát Cực Đạo của Tiên Tổ. Khi Vương Lâm thi triển, nó biểu hiện thành hư ảnh màu vàng.","detail":"Cực Kim Đạo được Vương Lâm huyễn hóa cùng các đạo khác trong lúc đối kháng Diệp Vi và đại trận Đạo Cổ hoàng cung.","nguon":["@c1922"],"congNang":["Huyễn hóa hư ảnh màu vàng trong lục đạo Bát Cực Đạo @c1922"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1922","tangDatToi":"đã thi triển","trangThai":"đang tu"}],"capNhatToi":"@c1922","tabs":{"tienTrinh":[{"chuong":"@c1922","loai":"thi triển","importance":"normal","giaiDoan":"Hư ảnh màu vàng","text":"Vương Lâm thi triển Cực Kim Đạo thành hư ảnh màu vàng trong thế đối kháng Diệp Vi.","anchor":"Hư ảnh màu vàng là Cực Kim Đạo"}]},"dinhDanh":"goc"},{"id":"tu-cuc-sinh-dao","name":"Tử Cực Sinh Đạo","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"Bát Cực Đạo của Tiên Tổ","soHuu":["Vương Lâm"],"blurb":"Tử Cực Sinh Đạo là đạo thứ sáu trong lục đạo Bát Cực Đạo mà Vương Lâm đã học được. Nó được nhắc khi hắn triển lộ thần thông trước Diệp Vi.","detail":"Tử Cực Sinh Đạo thuộc nhóm sáu đạo đã được Vương Lâm nắm giữ trong Bát Cực Đạo của Tiên Tổ ở giai đoạn này.","nguon":["@c1922"],"congNang":["Là đạo thứ sáu trong lục đạo Bát Cực Đạo mà Vương Lâm đã học được @c1922"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1922","tangDatToi":"đã học được","trangThai":"đang tu"}],"capNhatToi":"@c1922","tabs":{"tienTrinh":[{"chuong":"@c1922","loai":"hé lộ tầng-chiêu","importance":"normal","giaiDoan":"Đạo thứ sáu","text":"Tử Cực Sinh Đạo được nêu là một trong sáu đạo Bát Cực Đạo mà Vương Lâm đã nắm giữ.","anchor":"một đạo còn lại là Tử Cực Sinh Đạo"}]},"dinhDanh":"goc"},{"id":"luc-cuc-dao","name":"Lục Cực Đạo","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"Cực Đạo","soHuu":["Vương Lâm"],"blurb":"Đạo pháp được Vương Lâm thi triển để công kích sương mù mười màu dưới núi hoang.","detail":"Vương Lâm ngưng vòng khói xanh, vận Cực Đạo kim mộc thủy thổ cùng Sinh Tử Cực Đạo thứ sáu, tạo thành đồ hình hai màu đen trắng rồi đẩy thẳng vào sương mù mười màu.","thuocTinh":"Cực Đạo","uyLuc":"Dùng để phá sương mù mười màu che giấu quốc sư Đạo Cổ.","congNang":["Công kích sương mù mười màu bằng đồ hình Lục Cực Đạo @c1923"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1923","tangDatToi":"thi triển","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1923","loai":"thi triển","importance":"normal","giaiDoan":"Công kích sương mù mười màu","text":"Vương Lâm vận nhiều Cực Đạo, ngưng thành đồ hình Lục Cực Đạo và đánh vào sương mù mười màu.","anchor":"Theo Vương Lâm vung tay phải lên, đồ hình Lục Cực Đạo này lao thẳng tới đám sương mù mười màu kia"}]},"capNhatToi":"@c1923","nguon":["@c1923"]},{"id":"cuc-dao-kim-moc-thuy-tho","name":"Cực Đạo kim mộc thủy thổ","cn":"","loai":"than-thong","loaiLabel":"Đạo pháp","phamCap":"không rõ","hePhai":"Cực Đạo","soHuu":["Vương Lâm"],"blurb":"Bốn Cực Đạo được Vương Lâm vận ra ngoài thân khi ngưng tụ Lục Cực Đạo.","detail":"Bốn màu Cực Đạo kim, mộc, thủy, thổ hiện ra bên ngoài thân thể Vương Lâm, phối hợp Sinh Tử Cực Đạo thứ sáu để cấu thành đồ hình công kích sương mù.","thuocTinh":"kim mộc thủy thổ","congNang":["Hợp cùng Sinh Tử Cực Đạo thứ sáu để cấu thành Lục Cực Đạo @c1923"],"tabs":{"tienTrinh":[{"chuong":"@c1923","loai":"thi triển","importance":"normal","giaiDoan":"Hiện ra ngoài thân","text":"Bốn Cực Đạo kim mộc thủy thổ hiện ra ngoài thân Vương Lâm trong lúc hắn ngưng tụ Lục Cực Đạo.","anchor":"Cùng lúc đó Cực Đạo kim mộc thủy thổ bốn màu hiện ra ở bên ngoài thân thể Vương Lâm"}]},"capNhatToi":"@c1923","nguon":["@c1923"]},{"id":"sinh-tu-cuc-dao-thu-sau","name":"Sinh Tử Cực Đạo thứ sáu","cn":"","loai":"than-thong","loaiLabel":"Đạo pháp","phamCap":"không rõ","hePhai":"Cực Đạo","soHuu":["Vương Lâm"],"blurb":"Cực Đạo thứ sáu do Vương Lâm vận ra khi thi triển Lục Cực Đạo.","detail":"Sinh Tử Cực Đạo thứ sáu lóe lên và hóa thành đồ hình hai màu đen trắng trước người Vương Lâm, trở thành thành phần then chốt trong Lục Cực Đạo.","thuocTinh":"sinh tử","congNang":["Hóa thành đồ hình đen trắng trong Lục Cực Đạo @c1923"],"tabs":{"tienTrinh":[{"chuong":"@c1923","loai":"thi triển","importance":"normal","giaiDoan":"Hóa đồ hình đen trắng","text":"Sinh Tử Cực Đạo thứ sáu lóe lên và hóa thành đồ hình đen trắng trước người Vương Lâm.","anchor":"còn có Sinh Tử Cực Đạo thứ sáu cũng theo đó lóe lên"}]},"capNhatToi":"@c1923","nguon":["@c1923"]},{"id":"tran-phap-khong-lo-duoi-nui-hoang","name":"Trận pháp khổng lồ dưới núi hoang","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"không rõ","hePhai":"Đạo Cổ","soHuu":["Quốc sư thần bí của Đạo Cổ nhất mạch"],"blurb":"Trận pháp lộ ra sau khi Vương Lâm đánh sụp núi hoang, được sương mù mười màu che phủ.","detail":"Trận pháp khổng lồ nằm dưới núi hoang, lóe ánh sáng mười màu tạo thành sương mù mười màu. Một chưởng làm sụp núi của Vương Lâm không khiến trận pháp bị tổn hại.","dacDiem":"Có ánh sáng mười màu kết thành sương mù phòng hộ.","congNang":["Tạo sương mù mười màu che giấu quốc sư và hóa giải chưởng lực phá núi của Vương Lâm @c1923"],"tabs":{"tienTrinh":[{"chuong":"@c1923","loai":"xuất hiện","importance":"normal","giaiDoan":"Lộ dưới núi hoang","text":"Trận pháp khổng lồ lộ ra sau khi Vương Lâm đánh sụp núi, nhưng ánh sáng mười màu của nó vẫn không bị phá hủy.","anchor":"lộ ra trận pháp khổng lồ bên dưới. Nhưng trận pháp này lại lóe lên ánh sáng mười màu"}]},"capNhatToi":"@c1923","nguon":["@c1923"]},{"id":"thap-sac-huyen-vu-tran","name":"Thập sắc Huyền Vụ Trận","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"Đạo Cổ quốc sư","soHuu":["Thiên Vận Tử"],"blurb":"Thập sắc Huyền Vụ Trận là trận pháp sương mù mười màu do Thiên Vận Tử (quốc sư Đạo Cổ) bố trí, có khả năng huyễn hóa liên tiếp các mãnh thú từ sương mù để ngăn cản kẻ xâm nhập, đồng thời sở hữu tầng hợp nhất khi chín thú tụ lại thành con thú thứ mười.","detail":"Trong chương 1924, Thập sắc Huyền Vụ Trận lần đầu được gọi tên khi Thiên Vận Tử triển khai trận pháp này để cản bước Vương Lâm. Trận pháp vận hành bằng sương mù mười màu, liên tục sinh ra các mãnh thú huyễn hóa tấn công người xâm nhập. Thiên Vận Tử tự xưng đây là trận pháp của lão phu và nhận định rằng Lục Cực Đạo của Vương Lâm chưa đủ để tiến vào trận, chỉ có Bát Cực Đạo của Tiên Tổ mới có khả năng phá vỡ.","thuocTinh":"Sương mù mười màu","congNang":["Huyễn hóa nhiều mãnh thú liên tiếp từ sương mù để cản trở người xâm nhập @c1924","Chín thú huyễn hóa có thể tụ lại hợp nhất thành con thú thứ mười, tạo tầng uy lực cao hơn @c1924"],"chuHienThoi":"Thiên Vận Tử","trangThai":"đang vận hành","capNhatToi":"@c1924","tabs":{"tienTrinh":[{"chuong":"@c1924","loai":"xuất hiện","importance":"major","giaiDoan":"Đối đầu Vương Lâm","text":"Thập sắc Huyền Vụ Trận lần đầu được gọi tên khi Thiên Vận Tử dùng sương mù mười màu và các mãnh thú huyễn hóa để ngăn Vương Lâm tiến vào trung tâm trận.","anchor":"có thể phá vỡ được Thập sắc Huyền Vụ Trận của lão phu"}]},"nguon":["@c1924"],"uyLuc":"Theo lời Thiên Vận Tử, Lục Cực Đạo không đủ để phá trận, cần ít nhất Bát Cực Đạo của Tiên Tổ mới có khả năng phá vỡ @c1924","dacDiem":"Trận pháp dựa trên sương mù mười màu, các mãnh thú được huyễn hóa từ sương mù và có cơ chế hợp nhất chín thú thành con thú thứ mười."},{"id":"kim-ban-nguyen-luc","name":"Kim bản nguyên lực","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Bản nguyên thần thông","phamCap":"Không rõ","hePhai":"Ngũ hành bản nguyên","soHuu":["Vương Lâm"],"blurb":"Một nhánh lực lượng ngũ hành chân thân của Vương Lâm, biểu hiện bằng kim bản nguyên nồng đậm.","detail":"Trong Thập sắc Huyền Vụ Trận, kim bản nguyên lực của Vương Lâm hóa thành vô số tiểu kiếm màu vàng, cuốn thành lốc kiếm đánh vào cự thú đầu người thân sư.","thuocTinh":"Kim","congNang":["Hóa thành kiếm lốc màu vàng để công kích mãnh thú @c1924"],"chuHienThoi":"Vương Lâm","capNhatToi":"@c1924","tabs":{"tienTrinh":[{"chuong":"@c1924","loai":"thi triển","importance":"normal","giaiDoan":"Trấn áp mãnh thú đầu tiên","text":"Kim bản nguyên lực trong ngũ hành chân thân hóa thành vô số tiểu kiếm màu vàng, cuốn thành lốc kiếm đánh cự thú đầu người thân sư.","anchor":"bộc lộ ra kim bản nguyên lực nồng đậm ầm ầm đánh tới cự thú"}]},"nguon":["@c1924"]},{"id":"thuy-ban-nguyen-luc","name":"Thủy bản nguyên lực","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Bản nguyên thần thông","phamCap":"Không rõ","hePhai":"Ngũ hành bản nguyên","soHuu":["Vương Lâm"],"blurb":"Một nhánh lực lượng ngũ hành chân thân của Vương Lâm, biểu hiện bằng hơi nước và mưa kiếm.","detail":"Trong Thập sắc Huyền Vụ Trận, thủy bản nguyên lực tạo ra hơi nước rồi hóa thành vô số giọt mưa sắc bén như kiếm, xuyên thủng bọ ngựa sáu cánh từ sương mù lao ra.","thuocTinh":"Thủy","congNang":["Tạo mưa kiếm sắc bén để xuyên thủng mục tiêu @c1924"],"chuHienThoi":"Vương Lâm","capNhatToi":"@c1924","tabs":{"tienTrinh":[{"chuong":"@c1924","loai":"thi triển","importance":"normal","giaiDoan":"Đánh bọ ngựa sáu cánh","text":"Thủy bản nguyên lực hóa hơi nước thành vô số giọt mưa sắc bén như kiếm, xuyên thủng bọ ngựa sáu cánh tái xuất từ sương mù.","anchor":"hình thành vô số giọt mưa giống như những thanh kiếm sắc bén"}]},"nguon":["@c1924"]},{"id":"chan-than-dao-co","name":"Chân thân Đạo Cổ","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông bổn mạng Cổ Tộc","phamCap":"Không rõ","hePhai":"Cổ Tộc","soHuu":["Vương Lâm"],"blurb":"Chân thân Đạo Cổ là hình thái bổn mạng của tộc nhân Cổ Tộc, được Vương Lâm lần đầu hiển lộ trên Tiên Cương đại lục trong trận chiến bên trong Thập sắc Huyền Vụ Trận. Khi kích hoạt, thân thể bành trướng tới quy mô hàng trăm trượng, sở hữu sức mạnh thể phách đủ một quyền đánh nổ người khổng lồ hai đầu.","detail":"Trong trận giao tranh tại Thập sắc Huyền Vụ Trận trên Tiên Cương đại lục, Vương Lâm đối mặt người khổng lồ hai đầu và quyết định hiển lộ chân thân Đạo Cổ. Thân thể hắn từ hình dáng người thường bành trướng lên trăm trượng rồi tiếp tục tới bảy tám trăm trượng, hóa thành hình thái khổng lồ của Cổ Tộc. Dưới hình thái này, Vương Lâm dùng thuần túy lực thân thể một quyền đánh nổ người khổng lồ hai đầu rồi xông thẳng vào sương mù. Tuy nhiên, tộc nhân Cổ Tộc không dễ dàng hiển lộ chân thân, bởi nếu chân thân bị tổn hại thì ảnh hưởng rất lớn tới tu vi, đây là rủi ro cốt lõi khi sử dụng hình thái này.","thuocTinh":"Cổ Tộc","yeuCau":"Tộc nhân Cổ Tộc có chân thân bổn mạng","uyLuc":"Có thể khiến thân thể bành trướng tới quy mô khổng lồ và dùng thuần lực thân thể một quyền đánh nổ người khổng lồ hai đầu trong Thập sắc Huyền Vụ Trận @c1924","dacDiem":"Tộc nhân Cổ Tộc không dễ hiển lộ chân thân, vì nếu chân thân bị tổn hại sẽ ảnh hưởng rất lớn tới tu vi @c1924","congNang":["Hiển hóa thân thể Đạo Cổ khổng lồ, bành trướng từ trăm trượng tới bảy tám trăm trượng để giao chiến trực diện @c1924","Tăng cường sức mạnh thể phách tới mức một quyền đánh nổ người khổng lồ hai đầu trong Thập sắc Huyền Vụ Trận @c1924"],"chuHienThoi":"Vương Lâm","trangThai":"đã hiển lộ trên Tiên Cương đại lục","capNhatToi":"@c1924","nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1924","tangDatToi":"Lần đầu hiển lộ trên Tiên Cương đại lục","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1924","loai":"xuất hiện","importance":"major","giaiDoan":"Lần đầu trên Tiên Cương","text":"Vương Lâm lần đầu hiển lộ chân thân Đạo Cổ trên Tiên Cương đại lục, hóa thân khổng lồ để đánh nổ người khổng lồ hai đầu và xông vào trung tâm sương mù.","anchor":"Chân thân Đạo Cổ!"}]},"nguon":["@c1924"]},{"id":"truyen-tong-tran-dac-di","name":"Truyền Tống Trận đặc dị","cn":"","aliases":[],"loai":"khac","loaiLabel":"Trận pháp","phamCap":"không rõ","hePhai":"không rõ","soHuu":["Lão già trong trận pháp giống Thiên Vận Tử và Thất Thải Tiên Tôn"],"blurb":"Trận pháp dưới lão già được Vương Lâm nhận ra có bản chất truyền tống nhưng không chỉ dùng để dịch chuyển. Nó còn có tác dụng mở hoàn toàn một cánh cửa xa xưa và như tồn tại ở không gian khác.","detail":"Trận pháp vận chuyển giữa ngọn núi đổ nát, tỏa hào quang mười màu và phản chấn quyền cước thân thể Cổ tộc của Vương Lâm mà không tổn hại. Lão già xác nhận trận có thêm công dụng mở một cánh cửa xa xưa, đồng thời ngăn cách không gian khiến đòn đánh trực tiếp khó chạm tới trận và người ngồi trong đó.","dinhDanh":"goc","congNang":["Truyền tống và mở hoàn toàn một cánh cửa xa xưa @c1925","Tạo cách biệt không gian khiến đòn đánh của Vương Lâm xuyên qua mà không phá được trận @c1925"],"tabs":{"tienTrinh":[{"chuong":"@c1925","loai":"xuất hiện","importance":"normal","giaiDoan":"Vận chuyển trong núi đổ nát","text":"Trận pháp bị Vương Lâm nhận ra là truyền tống trận nhưng lão già xác nhận nó còn có tác dụng mở một cánh cửa xa xưa.","anchor":"Trận này quả thật là không chỉ có truyền tống, nó còn có một tác dụng khác"}]},"capNhatToi":"@c1925","nguon":["@c1925"]},{"id":"tran-phap-truyen-tong-tran-cua-dao-co-quoc-su","name":"Trận pháp / Truyền Tống Trận của Đạo Cổ quốc sư","cn":"","aliases":["Trận pháp của Đạo Cổ quốc sư","Truyền Tống Trận của Đạo Cổ quốc sư"],"loai":"khac","loaiLabel":"Trận pháp","phamCap":"không rõ","hePhai":"Đạo Cổ quốc sư","soHuu":["Thiên Vận Tử"],"blurb":"Trận pháp do Đạo Cổ quốc sư vận hành, tồn tại trong không gian khác nhưng có giao điểm với hiện thế. Trận pháp hấp thu tử khí hoàng cung, dẫn động tử hồn, duy trì tấm lưới ngăn cách không gian và liên quan trực tiếp đến con đường dẫn tới Thái Cổ Thần Cảnh.","detail":"Trận pháp này được Đạo Cổ quốc sư dùng máu để thúc đẩy vận chuyển, khiến tốc độ hoạt động tăng mạnh. Khi vận hành, trận pháp sinh ra tử hồn của những người từng chết trong tay Vương Lâm tại động phủ giới, đồng thời tạo ra tấm lưới không gian có tác dụng ngăn cách, cản trở Vương Lâm. Trận pháp nằm ở một không gian khác nhưng có giao điểm với hiện thế, hấp thu tử khí từ hoàng cung. Nó đóng vai trò then chốt trong lời thuyết phục của Đạo Cổ quốc sư về việc hồi sinh Lý Mộ Uyển và mở đường đi tới Thái Cổ Thần Cảnh.","dinhDanh":"goc","congNang":["Hấp thu tử khí từ hoàng cung @c1926","Tạo tấm lưới ngăn cách không gian, cản trở đối phương @c1926","Dẫn động tử hồn của những người từng bị giết tại động phủ giới @c1926","Liên quan đến việc mở đường tới Thái Cổ Thần Cảnh @c1926"],"nguoiTu":[{"ten":"Thiên Vận Tử","tuChuong":"@c1926","tangDatToi":"vận hành bằng máu","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1926","loai":"xuất hiện","importance":"major","giaiDoan":"vận hành bằng máu","text":"Đạo Cổ quốc sư dùng máu thúc trận pháp vận chuyển nhanh hơn, dẫn tử hồn và duy trì tấm lưới ngăn cách không gian.","anchor":"Nhưng cùng lúc này, trận pháp vận chuyển ầm ầm nhanh hơn trước mấy lần"}]},"capNhatToi":"@c1926","nguon":["@c1926"],"dacDiem":"Tồn tại trong không gian khác nhưng có giao điểm với hiện thế; được Đạo Cổ quốc sư dùng máu để thúc đẩy vận chuyển, khiến tốc độ vận hành tăng mạnh."},{"id":"than-thong-buoc-qua-khong-gian","name":"Thần thông bước qua không gian","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Thần thông giúp Vương Lâm mượn lực Đại Thiên Tôn chi dương, thân thể và tu vi để đạp qua ranh giới hai không gian. Trong chương này, hắn dùng nó để phá lưới ngăn giữa hiện thế và không gian trận pháp.","detail":"Vương Lâm thiêu đốt Đại Thiên Tôn chi dương để đổi lấy lực phá hư không, rồi bằng thân thể và tu vi cưỡng ép bước vào không gian trận pháp. Bước đi này được ví với việc từ động phủ giới bước vào Tiên Cương đại lục, nhưng vẫn bị tấm lưới không gian của Đạo Cổ quốc sư cản trở.","dinhDanh":"goc","congNang":["Vượt ranh giới giữa không gian hiện tại và không gian trận pháp @c1926"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1926","tangDatToi":"cưỡng ép đạp vào không gian trận pháp","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1926","loai":"thi triển","importance":"normal","giaiDoan":"vượt không gian","text":"Vương Lâm dùng lực Đại Thiên Tôn chi dương cùng thân thể và tu vi để bước từ không gian hiện tại vào không gian của trận pháp.","anchor":"dựa vào thân thể cường hãn và tu vi của mình mà từ không gian này bước vào không gian của trận pháp"}]},"capNhatToi":"@c1926","nguon":["@c1926"]},{"id":"sat-luc-chan-than-luc-mac","name":"Sát lục chân thân Lục Mặc","cn":"","aliases":["chân thân sát lục Lục Mặc","sát lục chân thân tóc đen"],"loai":"than-thong","loaiLabel":"Chân thân","phamCap":"không rõ","hePhai":"Vương Lâm","soHuu":["Vương Lâm","Lục Mặc"],"blurb":"Sát lục chân thân Lục Mặc là hình thể tóc đen do hắc khí của Vương Lâm ngưng tụ bên trong không gian trận pháp, xuất hiện khi bản thể không thể trực tiếp xâm nhập. Chân thân này mang khí chất lạnh lùng vô tình, đối diện Đạo Cổ quốc sư và phóng vô số tơ đen nhắm hủy diệt trận pháp.","detail":"Khi bản thể Vương Lâm không thể hoàn toàn vượt qua tấm lưới không gian, hắn đưa hắc khí vào lỗ hổng đang khép lại. Hắc khí ngưng tụ thành một Vương Lâm tóc đen bên trong không gian trận pháp, được Đạo Cổ quốc sư gọi tên là Lục Mặc. Chân thân này hiện diện trước mặt Đạo Cổ quốc sư với khí chất lạnh lùng vô tình, trực tiếp triển khai công kích nhắm vào trận pháp.","dinhDanh":"goc","thuocTinh":"sát lục","dacDiem":"Tóc đen, khí chất lạnh lùng vô tình, xuất hiện bằng hắc khí của Vương Lâm.","congNang":["Ngưng tụ thành chân thân trong không gian trận pháp từ hắc khí của Vương Lâm lọt qua lỗ hổng không gian @c1926","Phóng vô số tơ đen để chuẩn bị hủy diệt trận pháp @c1926"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1926","tangDatToi":"đưa vào không gian trận pháp","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1926","loai":"xuất hiện","importance":"major","giaiDoan":"hiện thân Lục Mặc","text":"Hắc khí của Vương Lâm lọt qua lỗ hổng không gian và ngưng thành sát lục chân thân tóc đen Lục Mặc trước mặt Đạo Cổ quốc sư.","anchor":"hắc khí ngưng tụ lại hóa thành một Vương Lâm với mái tóc đen kịt"}]},"capNhatToi":"@c1926","nguon":["@c1926"]},{"id":"tran-phap-dan-dong-sat-luc-tu-hon","name":"Trận pháp dẫn động sát lục tử hồn","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"Đạo Cổ quốc sư","soHuu":["Thiên Vận Tử"],"blurb":"Trận pháp do Thiên Vận Tử vận chuyển bằng máu tươi, cần sát lục tử hồn do bản thể Vương Lâm tạo ra để dẫn động dị tượng Thái Cổ Thần Cảnh.","detail":"Trận này kéo tử hồn sát lục hóa thành hắc khí, kết hợp với vòng xoáy trên trời và các cây cột chống trời để mở đường tới Thái Cổ Thần Cảnh. Lục Mặc chất vấn vì sao trận pháp phải cần sát lục tử hồn của Vương Lâm, nhưng bí mật cốt lõi bị phép tắc giới luật ngăn tiết lộ.","congNang":["Dẫn động tử hồn sát lục hóa thành hắc khí và tạo dị tượng mở Thái Cổ Thần Cảnh @c1927"],"tabs":{"tienTrinh":[{"chuong":"@c1927","loai":"xuất hiện","importance":"normal","giaiDoan":"Dẫn động tử hồn","text":"Trận pháp được Thiên Vận Tử dùng máu tươi vận chuyển, cần sát lục tử hồn của Vương Lâm để tiếp tục mở dị tượng Thái Cổ Thần Cảnh.","anchor":"vì sao trận này phải cần tới sát lục tử hồn của bản thể ta mới có thể dẫn động được"}]},"capNhatToi":"@c1927","nguon":["@c1927"]},{"id":"suc-manh-pha-gioi-cua-vuong-lam","name":"Sức mạnh phá giới của Vương Lâm","cn":"","loai":"than-thong","loaiLabel":"Năng lực phá giới","phamCap":"Không rõ","hePhai":"Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Năng lực giúp Vương Lâm đưa sát lục chân thân tới không gian trận pháp, vượt ngoài dự liệu của Thiên Vận Tử.","detail":"Thiên Vận Tử vốn không ngờ Vương Lâm có được sức mạnh phá giới, khiến sát lục chân thân có thể xuất hiện tại nơi trận pháp vận chuyển và làm kế hoạch của hắn mất thế chủ động.","congNang":["Đưa sát lục chân thân vượt giới tới vị trí trận pháp @c1927"],"tabs":{"tienTrinh":[{"chuong":"@c1927","loai":"xuất hiện","importance":"normal","giaiDoan":"Vượt giới tới trận pháp","text":"Thiên Vận Tử nhận ra Vương Lâm có sức mạnh phá giới, khiến sát lục chân thân có thể tới gần trận pháp ngoài dự tính của hắn.","anchor":"không ngờ tới đối phương lại có thể có được sức mạnh phá giới"}]},"capNhatToi":"@c1927","nguon":["@c1927"]},{"id":"phep-tac-gioi-luat","name":"Phép tắc giới luật","cn":"","loai":"khac","loaiLabel":"Quy tắc cấm chế","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":[],"blurb":"Quy tắc vô hình ngăn Thiên Vận Tử tiết lộ bí mật cốt lõi liên quan Thái Cổ Thần Cảnh.","detail":"Khi Thiên Vận Tử định nói vì sao trận pháp cần sát lục tử hồn và hé lộ phần sâu hơn về thân phận, thân thể hắn run rẩy gần tiêu tán. Hắn tự nói nếu tiết lộ sẽ bị hình thần câu diệt.","congNang":["Cấm tiết lộ bí mật liên quan Thái Cổ Thần Cảnh, người vi phạm có nguy cơ hình thần câu diệt @c1927"],"tabs":{"tienTrinh":[{"chuong":"@c1927","loai":"xuất hiện","importance":"normal","giaiDoan":"Ngăn tiết lộ bí mật","text":"Phép tắc giới luật xuất hiện khi Thiên Vận Tử định nói bí mật, khiến thân thể hắn run rẩy và buộc phải dừng lời.","anchor":"Đây là… đây là phép tắc giới luật! Không thể nói được"}]},"capNhatToi":"@c1927","nguon":["@c1927"]},{"id":"tran-phap-cua-dao-co-quoc-su","name":"Trận pháp của Đạo Cổ quốc sư","cn":"","aliases":[],"loai":"khac","loaiLabel":"Trận pháp","phamCap":"không rõ","hePhai":"Đạo Cổ quốc sư","soHuu":["Thiên Vận Tử"],"blurb":"Trận pháp được Thiên Vận Tử vận chuyển trong ngọn núi đổ nát để phá lưới ngăn hai giới. Nó chuyển từ hình chiếu hư ảo thành tồn tại chân thật trên Tiên Cương và tạo cột sáng thứ chín.","detail":"Đạo Cổ quốc sư dùng trận pháp phát sáng, phá lưới ngăn cách hai giới, khiến trận pháp vốn ở trạng thái hình chiếu được truyền vào Tiên Cương đại lục. Trận pháp còn mang theo chân thân sát lục của Vương Lâm và trở thành nền tảng tạo cây cột thứ chín mở cơ chế Thái Cổ Thần Cảnh.","congNang":["Phá lưới ngăn hai giới và na di hình chiếu trận pháp thành tồn tại chân thật trên Tiên Cương @c1928","Đưa chân thân sát lục của Vương Lâm vào cùng không gian với bản thể và tạo cột sáng thứ chín @c1928"],"nguoiTu":[{"ten":"Thiên Vận Tử","tuChuong":"@c1928","tangDatToi":"vận chuyển trận pháp","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1928","loai":"xuất hiện","importance":"normal","giaiDoan":"Phá lưới hai giới","text":"Trận pháp của Đạo Cổ quốc sư được truyền vào Tiên Cương đại lục, từ hình chiếu hư ảo chuyển thành tồn tại chân thật và tạo cột sáng thứ chín.","anchor":"Trận pháp này không ngờ bị Đạo Cổ quốc sư không biết dùng phương pháp gì truyền từ không gian này vào trong Tiên Cương đại lục"}]},"dinhDanh":"goc","capNhatToi":"@c1928","nguon":["@c1928"]},{"id":"loi-thi-thao-vo-luong-kiep-cua-dao-co-quoc-su","name":"Lời thì thào vô lượng kiếp của Đạo Cổ quốc sư","cn":"","aliases":[],"loai":"bi-thuat","loaiLabel":"Chú ngữ / nghi thức","phamCap":"không rõ","hePhai":"Đạo Cổ quốc sư","soHuu":["Thiên Vận Tử"],"blurb":"Chú ngữ kỳ dị do Đạo Cổ quốc sư niệm khi kích hoạt trận pháp. Vô số tiếng thì thào hợp thành lời về thiên đạo, vô lượng kiếp và phụng chí tu hành.","detail":"Trong lúc vận chuyển trận pháp, Đạo Cổ quốc sư niệm những tiếng thì thào như vô số người cùng nói. Các tiếng ấy cuối cùng hợp thành một câu, trở thành nghi thức kích phát trận pháp phá lưới hai giới.","congNang":["Kích hoạt trận pháp của Đạo Cổ quốc sư trong nghi thức mở cơ chế Thái Cổ Thần Cảnh @c1928"],"nguoiTu":[{"ten":"Thiên Vận Tử","tuChuong":"@c1928","tangDatToi":"thi triển chú ngữ","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1928","loai":"thi triển","importance":"normal","giaiDoan":"Kích phát trận pháp","text":"Đạo Cổ quốc sư niệm lời thì thào kỳ dị, khiến các âm thanh hợp lại thành câu và kích phát trận pháp.","anchor":"Vô số câu thì thào của Đạo Cổ quốc sư sau đó bất ngờ biến thành một câu nói"}]},"dinhDanh":"goc","capNhatToi":"@c1928","nguon":["@c1928"]},{"id":"co-che-chin-cay-cot-mo-thai-co-than-canh","name":"Cơ chế chín cây cột mở Thái Cổ Thần Cảnh","cn":"","aliases":[],"loai":"khac","loaiLabel":"Đại trận / cơ chế không gian","phamCap":"không rõ","hePhai":"Thái Cổ Thần Cảnh","soHuu":[],"blurb":"Cơ chế không gian hình thành từ chín cây cột thông thiên, khi cây cột thứ chín rơi vào trung tâm vòng tròn tám cột ngoài biển, toàn bộ hợp nhất tạo nên cánh cửa khổng lồ của Thái Cổ Thần Cảnh. Quá trình vận hành khiến biển cả bị nhấc dựng đứng thành vách ngăn giữa Cổ Tộc và Tiên Tộc.","detail":"Sau khi cây cột thứ chín rơi vào trung tâm vòng tròn do tám cây cột ngoài biển tạo thành, biển rộng chấn động dữ dội, mặt nước bị nhấc lên dựng thẳng thành bức vách tường khổng lồ ngăn cách lãnh địa Cổ Tộc và Tiên Tộc. Chín cây cột xoay nhanh trong cơn lốc nước và hợp nhất thành một cánh cửa khổng lồ của Thái Cổ Thần Cảnh, tuy nhiên cánh cửa này vẫn còn đóng chặt tại thời điểm ghi nhận.","congNang":["Hình thành cánh cửa khổng lồ của Thái Cổ Thần Cảnh từ chín cây cột thông thiên @c1928","Nhấc biển rộng dựng thẳng thành vách ngăn giữa Cổ Tộc và Tiên Tộc @c1928"],"tabs":{"tienTrinh":[{"chuong":"@c1928","loai":"xuất hiện","importance":"major","giaiDoan":"Cửa Thần Cảnh hình thành","text":"Tám cột ngoài biển kết hợp cây cột thứ chín, khiến biển dựng thẳng và hợp thành cánh cửa Thái Cổ Thần Cảnh còn đóng chặt.","anchor":"Mơ hồ có thể nhìn thấy trong cơn lốc này chín cây cột phát ra ánh sáng, hợp thành một cánh cửa khổng lồ"}]},"dinhDanh":"goc","capNhatToi":"@c1928","nguon":["@c1928"],"uyLuc":"Nhấc cả biển rộng dựng đứng thành bức tường ngăn cách hai đại thế lực Cổ Tộc và Tiên Tộc, đồng thời chín cột xoay trong cơn lốc nước hợp thành cửa Thái Cổ Thần Cảnh.","dacDiem":"Cần đủ chín cây cột thông thiên mới kích hoạt; tám cột xếp vòng tròn ngoài biển, cột thứ chín rơi vào trung tâm làm mấu chốt khởi động toàn bộ cơ chế; cánh cửa Thái Cổ Thần Cảnh hình thành nhưng vẫn đóng chặt tại thời điểm ghi nhận."},{"id":"than-thong-quan-sat-thai-co-than-canh","name":"Thần thông quan sát Thái Cổ Thần Cảnh","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"nhiều cao thủ Tiên Cương","soHuu":[],"blurb":"Các cao thủ trên Tiên Cương đại lục dùng nhiều loại thần thông để tới vùng biển nơi Thái Cổ Thần Cảnh hiện ra quan sát dị tượng.","detail":"Khi Thái Cổ Thần Cảnh hiện ra tại vùng biển giữa Tiên Tộc và Cổ Tộc, rất nhiều người dùng đủ loại thần thông đi tới. Họ chủ yếu quan sát cánh cửa và cơn lốc nước biển rồi trầm mặc rời đi.","congNang":["Đưa người thi triển tới quan sát dị tượng Thái Cổ Thần Cảnh tại vùng biển giữa Tiên Tộc và Cổ Tộc @c1929"],"tabs":{"tienTrinh":[{"chuong":"@c1929","loai":"thi triển","importance":"normal","giaiDoan":"Thái Cổ Thần Cảnh hiện ra","text":"Nhiều cao thủ dùng các loại thần thông đi tới vùng biển để quan sát Thái Cổ Thần Cảnh.","anchor":"khiến cho rất nhiều người bằng đủ loại thần thông đi tới"}]},"nguon":["@c1929"]}]};
